@@ -84,7 +84,7 @@
         "helm install contour bitnami/contour --version 21.1.4 --namespace contour --create-namespace",
         "kubectl get pods -n contour",
         "kubectl set resources deployment contour --namespace contour --limits=cpu=500m,memory=512Mi --requests=cpu=250m,memory=256Mi",
-        "kubectl apply -f https://projectcontour.io/docs/main/contour-rbac.yaml"
+        "kubectl get clusterrolebindings | grep contour"
       ]
     }
   },

@@ -24,7 +24,7 @@
       },
       {
         "title": "Configure Kyverno policies",
-        "description": "Set up the desired policies by modifying the `values.yaml` file or directly applying policies. For example, to set the Pod Security Standard:\n```bash\nkubectl apply -f https://raw.githubusercontent.com/kyverno/policies/main/pod-security/pod-security-standard.yaml\n```"
+        "description": "Set up the desired policies by modifying the `values.yaml` file or directly applying policies. Install the Pod Security Standards policies from the official Helm chart:\n```bash\nhelm install kyverno-policies kyverno/kyverno-policies --namespace kyverno\n```"
       }
     ],
     "uninstall": [
@@ -79,7 +79,7 @@
         "helm repo add kyverno https://kyverno.github.io/kyverno\nhelm repo update",
         "helm install kyverno kyverno/kyverno --version 3.7.1 --namespace kyverno --create-namespace",
         "kubectl get pods -n kyverno",
-        "kubectl apply -f https://raw.githubusercontent.com/kyverno/policies/main/pod-security/pod-security-standard.yaml"
+        "helm install kyverno-policies kyverno/kyverno-policies --namespace kyverno"
       ]
     }
